  describe('state invariants (stateful PBT)', () => {
    it('always: valid-type', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ node: fc.string(), type: fc.string({ minLength: 1, maxLength: 50 }), content: fc.string({ minLength: 1, maxLength: 50 }), createdBy: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('update'), input: fc.record({ node: fc.string(), content: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ node: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ node: fc.string() }) }),
              fc.record({ action: fc.constant('setMetadata'), input: fc.record({ node: fc.string(), metadata: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('listBySchema'), input: fc.record({ schema: fc.string({ minLength: 1, maxLength: 50 }), limit: fc.string(), offset: fc.string() }) }),
              fc.record({ action: fc.constant('changeType'), input: fc.record({ node: fc.string(), type: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('clone'), input: fc.record({ source: fc.string({ minLength: 1, maxLength: 50 }), newId: fc.string({ minLength: 1, maxLength: 50 }), includeChildren: fc.boolean() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = contentNodeHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(contentNodeHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphaned-content', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ node: fc.string(), type: fc.string({ minLength: 1, maxLength: 50 }), content: fc.string({ minLength: 1, maxLength: 50 }), createdBy: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('update'), input: fc.record({ node: fc.string(), content: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ node: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ node: fc.string() }) }),
              fc.record({ action: fc.constant('setMetadata'), input: fc.record({ node: fc.string(), metadata: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('listBySchema'), input: fc.record({ schema: fc.string({ minLength: 1, maxLength: 50 }), limit: fc.string(), offset: fc.string() }) }),
              fc.record({ action: fc.constant('changeType'), input: fc.record({ node: fc.string(), type: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('clone'), input: fc.record({ source: fc.string({ minLength: 1, maxLength: 50 }), newId: fc.string({ minLength: 1, maxLength: 50 }), includeChildren: fc.boolean() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = contentNodeHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(contentNodeHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: orphaned-content
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

